434	# ---------------------------------------------------------------------------
435	# Microphone pixmap helper (shared with tray)
436	# ---------------------------------------------------------------------------
437	
438	
439	# Кеш микрофонных pixmap по ключу (size, rgba). Иконку трея перерисовывают
440	# на каждое state-изменение — без кеша это лишние ~0.5 ms × N + аллокации.
441	_MIC_PIXMAP_CACHE: dict[tuple[int, int], QPixmap] = {}
442	_MIC_PIXMAP_CACHE_LIMIT = 64
443	
444	
445	def make_mic_pixmap(size: int, color: QColor | None = None) -> QPixmap:
446	    """Элегантная иконка микрофона на прозрачном фоне.
447	
448	    Дизайн:
449	      • Слегка вытянутая капсула с мягким бликом сверху для объёма.
450	      • Тонкая дуга-подставка с более изящными пропорциями.
451	      • Скруглённая горизонтальная база (короткая капсула, не линия).
452	      • Звуковые волны (две тонкие дуги) по бокам — только на больших
453	        размерах (>= 40 px), чтобы не загрязнять трей.
454	    Хорошо читается на 16-22 px, выглядит дорого на 64-256 px.
455	
456	    Кешируется по (size, rgba) — повторные вызовы возвращают тот же QPixmap.
457	    """
458	    c = color or QColor(0x1A, 0x1A, 0x1A)
459	    cache_key = (int(size), c.rgba())
460	    cached = _MIC_PIXMAP_CACHE.get(cache_key)
461	    if cached is not None:
462	        return cached
463	    pix = QPixmap(QSize(size, size))
464	    pix.fill(Qt.GlobalColor.transparent)
465	    p = QPainter(pix)
466	    p.setRenderHint(QPainter.RenderHint.Antialiasing)
467	
468	    s = float(size)
469	
470	    # ----- Капсула микрофона -----
471	    cap_w = s * 0.32
472	    cap_h = s * 0.52
473	    cap_x = (s - cap_w) / 2
474	    cap_y = s * 0.08
475	    p.setBrush(c)
476	    p.setPen(Qt.PenStyle.NoPen)
477	    p.drawRoundedRect(QRectF(cap_x, cap_y, cap_w, cap_h), cap_w / 2, cap_w / 2)
478	
479	    # ----- Блик в верхней части капсулы -----
480	    if s >= 22:
481	        highlight = QColor(255, 255, 255, 80)
482	        p.setBrush(highlight)
483	        hl_w = cap_w * 0.20
484	        hl_h = cap_h * 0.32
485	        hl_x = cap_x + cap_w * 0.22
486	        hl_y = cap_y + cap_h * 0.10
487	        p.drawRoundedRect(QRectF(hl_x, hl_y, hl_w, hl_h), hl_w * 0.5, hl_w * 0.5)
488	
489	    # ----- Дуга-подставка -----
490	    arc_w = max(1.4, s * 0.075)
491	    pen = QPen(c, arc_w)
492	    pen.setCapStyle(Qt.PenCapStyle.RoundCap)
493	    p.setPen(pen)
494	    p.setBrush(Qt.BrushStyle.NoBrush)
495	    arc_rect = QRectF(s * 0.18, s * 0.40, s * 0.64, s * 0.40)
496	    p.drawArc(arc_rect, 0, -180 * 16)
497	
498	    # ----- Стойка -----
499	    p.drawLine(QPointF(s / 2, s * 0.74), QPointF(s / 2, s * 0.86))
500	
501	    # ----- База: маленькая горизонтальная капсула -----
502	    base_h = max(1.6, s * 0.07)
503	    base_w = s * 0.32
504	    base_x = (s - base_w) / 2
505	    base_y = s * 0.86
506	    p.setBrush(c)
507	    p.setPen(Qt.PenStyle.NoPen)
508	    p.drawRoundedRect(QRectF(base_x, base_y, base_w, base_h), base_h / 2, base_h / 2)
509	
510	    # ----- Звуковые волны по бокам (только на больших размерах) -----
511	    if s >= 40:
512	        wave_pen = QPen(c, max(1.0, s * 0.035))
513	        wave_pen.setCapStyle(Qt.PenCapStyle.RoundCap)
514	        p.setPen(wave_pen)
515	        p.setBrush(Qt.BrushStyle.NoBrush)
516	
517	        # Внутренняя пара дуг (ближе к капсуле)
518	        inner_rect_l = QRectF(s * 0.05, s * 0.15, s * 0.20, s * 0.42)
519	        p.drawArc(inner_rect_l, -55 * 16, 110 * 16)
520	        inner_rect_r = QRectF(s * 0.75, s * 0.15, s * 0.20, s * 0.42)
521	        p.drawArc(inner_rect_r, 125 * 16, 110 * 16)
522	
523	        # Внешняя пара дуг — только на самых больших
524	        if s >= 96:
525	            outer_rect_l = QRectF(s * -0.02, s * 0.08, s * 0.30, s * 0.56)
526	            p.drawArc(outer_rect_l, -50 * 16, 100 * 16)
527	            outer_rect_r = QRectF(s * 0.72, s * 0.08, s * 0.30, s * 0.56)
528	            p.drawArc(outer_rect_r, 130 * 16, 100 * 16)
529	
530	    p.end()
531	
532	    # Сохраняем в кеш с простым ограничением размера (FIFO drop).
533	    if len(_MIC_PIXMAP_CACHE) >= _MIC_PIXMAP_CACHE_LIMIT:
534	        _MIC_PIXMAP_CACHE.pop(next(iter(_MIC_PIXMAP_CACHE)))
535	    _MIC_PIXMAP_CACHE[cache_key] = pix
536	    return pix
537	
538	
539	# ---------------------------------------------------------------------------
540	# Apple-style icon helpers (squircle tiles, SF Symbols-like glyphs)
541	# ---------------------------------------------------------------------------
542	
543	
544	def _squircle_path(rect: QRectF, radius_ratio: float = 0.225) -> QPainterPath:
545	    """Apple "squircle": rounded rect с непрерывной кривизной (≈G2-continuous).
546	
547	    Реализуется через QPainterPath с скруглением через arcTo по периметру.
548	    radius_ratio 0.225 даёт пропорции, близкие к macOS app icon.
549	    """
550	    path = QPainterPath()
551	    r = min(rect.width(), rect.height()) * radius_ratio
552	    path.addRoundedRect(rect, r, r)
553	    return path
554	
555	
556	def make_app_icon_pixmap(size: int) -> QPixmap:
557	    """Apple-style app icon: синий squircle с белым микрофоном внутри.
558	
559	    Используется для setWindowIcon, главной страницы, About-секции и сборки .ico.
560	    Кешируется отдельно от tray-иконки (там нужен прозрачный фон).
561	    """
562	    cache_key = (int(size), -1)  # уникальный sentinel для app-icon кеша
563	    cached = _MIC_PIXMAP_CACHE.get(cache_key)
564	    if cached is not None:
565	        return cached
566	    pix = QPixmap(QSize(size, size))
567	    pix.fill(Qt.GlobalColor.transparent)
568	    p = QPainter(pix)
569	    p.setRenderHint(QPainter.RenderHint.Antialiasing)
570	    p.setRenderHint(QPainter.RenderHint.SmoothPixmapTransform)
571	
572	    s = float(size)
573	    rect = QRectF(0, 0, s, s)
574	
575	    # ----- Squircle background с градиентом (Apple-blue → deep blue) -----
576	    path = _squircle_path(rect, 0.225)
577	    grad = QLinearGradient(0, 0, 0, s)
578	    grad.setColorAt(0.0, QColor(0x4A, 0xA3, 0xFF))   # светлее сверху
579	    grad.setColorAt(1.0, QColor(0x00, 0x66, 0xD6))   # глубже снизу
580	    p.setBrush(grad)
581	    p.setPen(Qt.PenStyle.NoPen)
582	    p.drawPath(path)
583	
584	    # Тонкий внутренний highlight-rim сверху (как у iOS app icons)
585	    rim_pen = QPen(QColor(255, 255, 255, 60), max(1.0, s * 0.012))
586	    p.setPen(rim_pen)
587	    p.setBrush(Qt.BrushStyle.NoBrush)
588	    inset = max(1.0, s * 0.012)
589	    rim_rect = QRectF(inset, inset, s - 2 * inset, s - 2 * inset)
590	    p.drawPath(_squircle_path(rim_rect, 0.225))
591	
592	    # ----- Микрофон внутри (белый) -----
593	    white = QColor(255, 255, 255)
594	    p.setBrush(white)
595	    p.setPen(Qt.PenStyle.NoPen)
596	
597	    cap_w = s * 0.30
598	    cap_h = s * 0.46
599	    cap_x = (s - cap_w) / 2
600	    cap_y = s * 0.20
601	    p.drawRoundedRect(QRectF(cap_x, cap_y, cap_w, cap_h), cap_w / 2, cap_w / 2)
602	
603	    # Дуга-подставка
604	    arc_w = max(1.5, s * 0.06)
605	    pen = QPen(white, arc_w)
606	    pen.setCapStyle(Qt.PenCapStyle.RoundCap)
607	    p.setPen(pen)
608	    p.setBrush(Qt.BrushStyle.NoBrush)
609	    arc_rect = QRectF(s * 0.22, s * 0.46, s * 0.56, s * 0.34)
610	    p.drawArc(arc_rect, 0, -180 * 16)
611	
612	    # Стойка
613	    p.drawLine(QPointF(s / 2, s * 0.74), QPointF(s / 2, s * 0.84))
614	
615	    # База
616	    p.setBrush(white)
617	    p.setPen(Qt.PenStyle.NoPen)
618	    base_w = s * 0.28
619	    base_h = max(1.6, s * 0.05)
620	    base_x = (s - base_w) / 2
621	    base_y = s * 0.83
622	    p.drawRoundedRect(QRectF(base_x, base_y, base_w, base_h), base_h / 2, base_h / 2)
623	
624	    p.end()
625	
626	    if len(_MIC_PIXMAP_CACHE) >= _MIC_PIXMAP_CACHE_LIMIT:
627	        _MIC_PIXMAP_CACHE.pop(next(iter(_MIC_PIXMAP_CACHE)))
628	    _MIC_PIXMAP_CACHE[cache_key] = pix
629	    return pix
