632	def make_nav_icon_pixmap(kind: str, size: int = 18, *, selected: bool = False) -> QPixmap:
633	    """Squircle-плитка с SF-Symbols-подобной иконкой (для sidebar).
634	
635	    kind: home | history | settings | about
636	    Используется в навигации главного окна.
637	    Когда selected=True — плитка прозрачная белая (контраст с синим выделением).
638	    """
639	    cache_key = (int(size), hash((kind, selected)) & 0xFFFFFFFF)
640	    cached = _MIC_PIXMAP_CACHE.get(cache_key)
641	    if cached is not None:
642	        return cached
643	
644	    pix = QPixmap(QSize(size, size))
645	    pix.fill(Qt.GlobalColor.transparent)
646	    p = QPainter(pix)
647	    p.setRenderHint(QPainter.RenderHint.Antialiasing)
648	
649	    s = float(size)
650	    rect = QRectF(0, 0, s, s)
651	
652	    # Цвет плитки: при selected — полупрозрачный белый, иначе цветной по типу.
653	    if selected:
654	        tile_color = QColor(255, 255, 255, 70)
655	        glyph_color = QColor(255, 255, 255)
656	    else:
657	        tile_hex = _NAV_ICON_TILES.get(kind, "#8E8E93")
658	        tile_color = QColor(tile_hex)
659	        glyph_color = QColor(255, 255, 255)
660	
661	    # Squircle подложка
662	    p.setBrush(tile_color)
663	    p.setPen(Qt.PenStyle.NoPen)
664	    p.drawPath(_squircle_path(rect, 0.26))
665	
666	    # Глиф (тонкая линия, белая)
667	    pen = QPen(glyph_color, max(1.0, s * 0.10))
668	    pen.setCapStyle(Qt.PenCapStyle.RoundCap)
669	    pen.setJoinStyle(Qt.PenJoinStyle.RoundJoin)
670	    p.setPen(pen)
671	    p.setBrush(Qt.BrushStyle.NoBrush)
672	
673	    # Внутренний box для глифа
674	    inset = s * 0.22
675	    g = QRectF(inset, inset, s - 2 * inset, s - 2 * inset)
676	
677	    if kind == "home":
678	        # Дом: треугольная крыша + прямоугольник
679	        path = QPainterPath()
680	        path.moveTo(g.left(), g.center().y() + g.height() * 0.05)
681	        path.lineTo(g.center().x(), g.top())
682	        path.lineTo(g.right(), g.center().y() + g.height() * 0.05)
683	        p.drawPath(path)
684	        # «Стены»
685	        wall_top = g.center().y() + g.height() * 0.05
686	        path2 = QPainterPath()
687	        path2.moveTo(g.left() + g.width() * 0.12, wall_top)
688	        path2.lineTo(g.left() + g.width() * 0.12, g.bottom())
689	        path2.lineTo(g.right() - g.width() * 0.12, g.bottom())
690	        path2.lineTo(g.right() - g.width() * 0.12, wall_top)
691	        p.drawPath(path2)
692	    elif kind == "history":
693	        # Часы: круг + стрелки
694	        p.drawEllipse(g)
695	        cx, cy = g.center().x(), g.center().y()
696	        r = g.width() / 2
697	        p.drawLine(QPointF(cx, cy), QPointF(cx, cy - r * 0.55))
698	        p.drawLine(QPointF(cx, cy), QPointF(cx + r * 0.40, cy))
699	    elif kind == "settings":
700	        # Шестерёнка-минимализм: круг + 6 насечек
701	        # рисуем как восьмиугольную звезду, чтобы было читаемо в 18px
702	        cx, cy = g.center().x(), g.center().y()
703	        r_outer = g.width() / 2
704	        r_inner = r_outer * 0.62
705	        p.drawEllipse(QRectF(cx - r_inner * 0.45, cy - r_inner * 0.45,
706	                             r_inner * 0.9, r_inner * 0.9))
707	        import math as _m
708	        for i in range(8):
709	            ang = _m.radians(i * 45)
710	            x1 = cx + _m.cos(ang) * r_inner
711	            y1 = cy + _m.sin(ang) * r_inner
712	            x2 = cx + _m.cos(ang) * r_outer
713	            y2 = cy + _m.sin(ang) * r_outer
714	            p.drawLine(QPointF(x1, y1), QPointF(x2, y2))
715	    elif kind == "about":
716	        # Кружок «i»
717	        p.drawEllipse(g)
718	        cx, cy = g.center().x(), g.center().y()
719	        # Точка
720	        dot_r = max(1.0, s * 0.06)
721	        p.setBrush(glyph_color)
722	        p.setPen(Qt.PenStyle.NoPen)
723	        p.drawEllipse(QPointF(cx, cy - g.height() * 0.20), dot_r, dot_r)
724	        # Стержень
725	        stem_pen = QPen(glyph_color, max(1.0, s * 0.10))
726	        stem_pen.setCapStyle(Qt.PenCapStyle.RoundCap)
727	        p.setPen(stem_pen)
728	        p.drawLine(QPointF(cx, cy - g.height() * 0.05),
729	                   QPointF(cx, cy + g.height() * 0.25))
730	
731	    p.end()
732	
733	    if len(_MIC_PIXMAP_CACHE) >= _MIC_PIXMAP_CACHE_LIMIT:
734	        _MIC_PIXMAP_CACHE.pop(next(iter(_MIC_PIXMAP_CACHE)))
735	    _MIC_PIXMAP_CACHE[cache_key] = pix
736	    return pix
