814	class _HistoryEntry(NamedTuple):
815	    ts: datetime
816	    text: str
817	
818	
819	# Mtime-кеш чтения истории: повторные вызовы _read_history без изменений на диске
820	# возвращают тот же список — не открываем JSONL по второму разу.
821	_HISTORY_CACHE: dict[int, tuple[tuple[float, ...], list[_HistoryEntry]]] = {}
822	
823	
824	def _read_history(days: int = 7) -> list[_HistoryEntry]:
825	    root = app_data_dir() / "backups"
826	    if not root.exists():
827	        return []
828	
829	    # Собираем актуальные пути JSONL и их mtime — это «отпечаток» состояния диска.
830	    cutoff = datetime.now(UTC) - timedelta(days=days)
831	    files: list[tuple[Path, float]] = []
832	    for day_dir in sorted(root.iterdir(), reverse=True):
833	        if not day_dir.is_dir():
834	            continue
835	        try:
836	            day_dt = datetime.strptime(day_dir.name, "%Y-%m-%d").replace(tzinfo=UTC)
837	        except ValueError:
838	            continue
839	        if day_dt < cutoff:
840	            break
841	        jsonl = day_dir / "dictations.jsonl"
842	        if jsonl.exists():
843	            try:
844	                files.append((jsonl, jsonl.stat().st_mtime))
845	            except OSError:
846	                pass
847	
848	    fingerprint = tuple(m for _, m in files)
849	    cached = _HISTORY_CACHE.get(days)
850	    if cached is not None and cached[0] == fingerprint:
851	        return list(cached[1])  # копия — мутации UI не должны портить кеш
852	
853	    entries: list[_HistoryEntry] = []
854	    for jsonl, _mtime in files:
855	        try:
856	            text = jsonl.read_text(encoding="utf-8")
857	        except OSError:
858	            continue
859	        for line in text.splitlines():
860	            line = line.strip()
861	            if not line:
862	                continue
863	            try:
864	                obj = json.loads(line)
865	                ts = datetime.fromisoformat(obj["ts"])
866	                if not ts.tzinfo:
867	                    ts = ts.replace(tzinfo=UTC)
868	                entries.append(_HistoryEntry(ts=ts, text=obj["text"]))
869	            except Exception:
870	                continue
871	    entries.sort(key=lambda e: e.ts, reverse=True)
872	    _HISTORY_CACHE[days] = (fingerprint, list(entries))
873	    return entries
874	
875	
876	def _date_label(ts: datetime) -> str:
877	    today = datetime.now().date()
878	    d = ts.date()
879	    if d == today:
880	        return "Сегодня"
881	    if d == today - timedelta(days=1):
882	        return "Вчера"
883	    months = [
884	        "", "января", "февраля", "марта", "апреля", "мая", "июня",
885	        "июля", "августа", "сентября", "октября", "ноября", "декабря",
886	    ]
887	    return f"{d.day} {months[d.month]} {d.year}"
