1358	    def _reload_history(self) -> None:
1359	        while self._hist_layout.count() > 1:
1360	            item = self._hist_layout.takeAt(0)
1361	            if item.widget():
1362	                item.widget().deleteLater()
1363	
1364	        disk = _read_history(days=7)
1365	        combined = list(disk) + list(self._session_entries)
1366	        seen: set[tuple[str, str]] = set()
1367	        unique: list[_HistoryEntry] = []
1368	        for e in combined:
1369	            key = (e.ts.isoformat()[:16], e.text[:40])
1370	            if key not in seen:
1371	                seen.add(key)
1372	                unique.append(e)
1373	        unique.sort(key=lambda e: e.ts, reverse=True)
1374	
1375	        if not unique:
1376	            empty = QLabel(
1377	                "Нет записей за последние 7 дней.\nНачни диктовать — они появятся здесь."
1378	            )
1379	            empty.setObjectName("historyEmpty")
1380	            empty.setAlignment(Qt.AlignmentFlag.AlignCenter)
1381	            empty.setContentsMargins(0, 60, 0, 0)
1382	            self._hist_layout.insertWidget(0, empty)
1383	            return
1384	
1385	        # Group by date
1386	        current_date = ""
1387	        pos = 0
1388	        date_card: QFrame | None = None
1389	        date_card_layout: QVBoxLayout | None = None
1390	
1391	        for entry in unique:
1392	            local_ts = entry.ts.astimezone()
1393	            dl = _date_label(local_ts)
1394	            if dl != current_date:
1395	                # New date section
1396	                current_date = dl
1397	                if pos > 0:
1398	                    spacer = QWidget()
1399	                    spacer.setFixedHeight(20)
1400	                    spacer.setStyleSheet("background: transparent;")
1401	                    self._hist_layout.insertWidget(pos, spacer)
1402	                    pos += 1
1403	                date_lbl = QLabel(dl)
1404	                date_lbl.setObjectName("sectionHeader")
1405	                date_lbl.setContentsMargins(4, 0, 0, 8)
1406	                self._hist_layout.insertWidget(pos, date_lbl)
1407	                pos += 1
1408	                # New card for this date's entries
1409	                date_card = QFrame()
1410	                date_card.setObjectName("card")
1411	                date_card_layout = QVBoxLayout(date_card)
1412	                date_card_layout.setContentsMargins(0, 0, 0, 0)
1413	                date_card_layout.setSpacing(0)
1414	                self._hist_layout.insertWidget(pos, date_card)
1415	                pos += 1
1416	
1417	            assert date_card_layout is not None
1418	            if date_card_layout.count() > 0:
1419	                date_card_layout.addWidget(_h_divider())
1420	            date_card_layout.addWidget(self._make_history_row(local_ts, entry.text))
