"""Главное окно приложения — навигация по боковой панели в стиле macOS System Settings.

Открывается двойным кликом по иконке в трее.
Вкладки: Главная / История / Настройки / Справка.

Палитра вдохновлена macOS Sequoia System Settings: чистый светло-серый фон,
синий системный акцент, белые карточки с тонкими разделителями, sidebar с иконками
в цветных squircle-плитках.
"""

from __future__ import annotations

import json
import sys
from datetime import UTC, datetime, timedelta
from pathlib import Path
from typing import NamedTuple

from PySide6.QtCore import QPointF, QRectF, QSize, Qt, Signal
from PySide6.QtGui import (
    QColor,
    QIcon,
    QLinearGradient,
    QPainter,
    QPainterPath,
    QPen,
    QPixmap,
)
from PySide6.QtWidgets import (
    QButtonGroup,
    QDialog,
    QDialogButtonBox,
