    QWidget,
)

from voice_typing_ru import __version__
from voice_typing_ru.domain.config import AppConfig
from voice_typing_ru.infra.paths import app_data_dir

# ---------------------------------------------------------------------------
# Constants
# ---------------------------------------------------------------------------

