# Кеш микрофонных pixmap по ключу (size, rgba). Иконку трея перерисовывают
# на каждое state-изменение — без кеша это лишние ~0.5 ms × N + аллокации.
_MIC_PIXMAP_CACHE: dict[tuple[int, int], QPixmap] = {}
_MIC_PIXMAP_CACHE_LIMIT = 64


def make_mic_pixmap(size: int, color: QColor | None = None) -> QPixmap:
    """Элегантная иконка микрофона на прозрачном фоне.

    Дизайн:
      • Слегка вытянутая капсула с мягким бликом сверху для объёма.
      • Тонкая дуга-подставка с более изящными пропорциями.
      • Скруглённая горизонтальная база (короткая капсула, не линия).
      • Звуковые волны (две тонкие дуги) по бокам — только на больших
        размерах (>= 40 px), чтобы не загрязнять трей.
    Хорошо читается на 16-22 px, выглядит дорого на 64-256 px.

    Кешируется по (size, rgba) — повторные вызовы возвращают тот же QPixmap.
    """
    c = color or QColor(0x1A, 0x1A, 0x1A)
    cache_key = (int(size), c.rgba())
    cached = _MIC_PIXMAP_CACHE.get(cache_key)
    if cached is not None:
        return cached
    pix = QPixmap(QSize(size, size))
    pix.fill(Qt.GlobalColor.transparent)
    p = QPainter(pix)
    p.setRenderHint(QPainter.RenderHint.Antialiasing)

    s = float(size)

    # ----- Капсула микрофона -----
    cap_w = s * 0.32
    cap_h = s * 0.52
    cap_x = (s - cap_w) / 2
    cap_y = s * 0.08
    p.setBrush(c)
    p.setPen(Qt.PenStyle.NoPen)
    p.drawRoundedRect(QRectF(cap_x, cap_y, cap_w, cap_h), cap_w / 2, cap_w / 2)

    # ----- Блик в верхней части капсулы -----
    if s >= 22:
        highlight = QColor(255, 255, 255, 80)
        p.setBrush(highlight)
        hl_w = cap_w * 0.20
        hl_h = cap_h * 0.32
        hl_x = cap_x + cap_w * 0.22
        hl_y = cap_y + cap_h * 0.10
        p.drawRoundedRect(QRectF(hl_x, hl_y, hl_w, hl_h), hl_w * 0.5, hl_w * 0.5)

    # ----- Дуга-подставка -----
    arc_w = max(1.4, s * 0.075)
    pen = QPen(c, arc_w)
    pen.setCapStyle(Qt.PenCapStyle.RoundCap)
    p.setPen(pen)
    p.setBrush(Qt.BrushStyle.NoBrush)
    arc_rect = QRectF(s * 0.18, s * 0.40, s * 0.64, s * 0.40)
    p.drawArc(arc_rect, 0, -180 * 16)

    # ----- Стойка -----
    p.drawLine(QPointF(s / 2, s * 0.74), QPointF(s / 2, s * 0.86))

    # ----- База: маленькая горизонтальная капсула -----
    base_h = max(1.6, s * 0.07)
    base_w = s * 0.32
    base_x = (s - base_w) / 2
    base_y = s * 0.86
    p.setBrush(c)
    p.setPen(Qt.PenStyle.NoPen)
    p.drawRoundedRect(QRectF(base_x, base_y, base_w, base_h), base_h / 2, base_h / 2)

    # ----- Звуковые волны по бокам (только на больших размерах) -----
    if s >= 40:
        wave_pen = QPen(c, max(1.0, s * 0.035))
        wave_pen.setCapStyle(Qt.PenCapStyle.RoundCap)
        p.setPen(wave_pen)
        p.setBrush(Qt.BrushStyle.NoBrush)

        # Внутренняя пара дуг (ближе к капсуле)
        inner_rect_l = QRectF(s * 0.05, s * 0.15, s * 0.20, s * 0.42)
        p.drawArc(inner_rect_l, -55 * 16, 110 * 16)
        inner_rect_r = QRectF(s * 0.75, s * 0.15, s * 0.20, s * 0.42)
        p.drawArc(inner_rect_r, 125 * 16, 110 * 16)

        # Внешняя пара дуг — только на самых больших
        if s >= 96:
            outer_rect_l = QRectF(s * -0.02, s * 0.08, s * 0.30, s * 0.56)
            p.drawArc(outer_rect_l, -50 * 16, 100 * 16)
            outer_rect_r = QRectF(s * 0.72, s * 0.08, s * 0.30, s * 0.56)
            p.drawArc(outer_rect_r, 130 * 16, 100 * 16)

    p.end()

    # Сохраняем в кеш с простым ограничением размера (FIFO drop).
    if len(_MIC_PIXMAP_CACHE) >= _MIC_PIXMAP_CACHE_LIMIT:
        _MIC_PIXMAP_CACHE.pop(next(iter(_MIC_PIXMAP_CACHE)))
    _MIC_PIXMAP_CACHE[cache_key] = pix
    return pix


# ---------------------------------------------------------------------------
# Apple-style icon helpers (squircle tiles, SF Symbols-like glyphs)
# ---------------------------------------------------------------------------


def _squircle_path(rect: QRectF, radius_ratio: float = 0.225) -> QPainterPath:
    """Apple "squircle": rounded rect с непрерывной кривизной (≈G2-continuous).

    Реализуется через QPainterPath с скруглением через arcTo по периметру.
    radius_ratio 0.225 даёт пропорции, близкие к macOS app icon.
    """
    path = QPainterPath()
    r = min(rect.width(), rect.height()) * radius_ratio
    path.addRoundedRect(rect, r, r)
    return path


def make_app_icon_pixmap(size: int) -> QPixmap:
    """Apple-style app icon: синий squircle с белым микрофоном внутри.

    Используется для setWindowIcon, главной страницы, About-секции и сборки .ico.
    Кешируется отдельно от tray-иконки (там нужен прозрачный фон).
    """
    cache_key = (int(size), -1)  # уникальный sentinel для app-icon кеша
    cached = _MIC_PIXMAP_CACHE.get(cache_key)
    if cached is not None:
        return cached
    pix = QPixmap(QSize(size, size))
    pix.fill(Qt.GlobalColor.transparent)
    p = QPainter(pix)
    p.setRenderHint(QPainter.RenderHint.Antialiasing)
    p.setRenderHint(QPainter.RenderHint.SmoothPixmapTransform)

    s = float(size)
    rect = QRectF(0, 0, s, s)

    # ----- Squircle background с градиентом (Apple-blue → deep blue) -----
    path = _squircle_path(rect, 0.225)
    grad = QLinearGradient(0, 0, 0, s)
    grad.setColorAt(0.0, QColor(0x4A, 0xA3, 0xFF))   # светлее сверху
    grad.setColorAt(1.0, QColor(0x00, 0x66, 0xD6))   # глубже снизу
    p.setBrush(grad)
    p.setPen(Qt.PenStyle.NoPen)
    p.drawPath(path)

    # Тонкий внутренний highlight-rim сверху (как у iOS app icons)
    rim_pen = QPen(QColor(255, 255, 255, 60), max(1.0, s * 0.012))
    p.setPen(rim_pen)
    p.setBrush(Qt.BrushStyle.NoBrush)
    inset = max(1.0, s * 0.012)
    rim_rect = QRectF(inset, inset, s - 2 * inset, s - 2 * inset)
    p.drawPath(_squircle_path(rim_rect, 0.225))

    # ----- Микрофон внутри (белый) -----
    white = QColor(255, 255, 255)
    p.setBrush(white)
    p.setPen(Qt.PenStyle.NoPen)

    cap_w = s * 0.30
    cap_h = s * 0.46
    cap_x = (s - cap_w) / 2
    cap_y = s * 0.20
    p.drawRoundedRect(QRectF(cap_x, cap_y, cap_w, cap_h), cap_w / 2, cap_w / 2)

    # Дуга-подставка
    arc_w = max(1.5, s * 0.06)
    pen = QPen(white, arc_w)
    pen.setCapStyle(Qt.PenCapStyle.RoundCap)
    p.setPen(pen)
    p.setBrush(Qt.BrushStyle.NoBrush)
    arc_rect = QRectF(s * 0.22, s * 0.46, s * 0.56, s * 0.34)
    p.drawArc(arc_rect, 0, -180 * 16)

    # Стойка
    p.drawLine(QPointF(s / 2, s * 0.74), QPointF(s / 2, s * 0.84))

    # База
    p.setBrush(white)
    p.setPen(Qt.PenStyle.NoPen)
    base_w = s * 0.28
    base_h = max(1.6, s * 0.05)
    base_x = (s - base_w) / 2
    base_y = s * 0.83
    p.drawRoundedRect(QRectF(base_x, base_y, base_w, base_h), base_h / 2, base_h / 2)

    p.end()

    if len(_MIC_PIXMAP_CACHE) >= _MIC_PIXMAP_CACHE_LIMIT:
        _MIC_PIXMAP_CACHE.pop(next(iter(_MIC_PIXMAP_CACHE)))
    _MIC_PIXMAP_CACHE[cache_key] = pix
    return pix


def make_nav_icon_pixmap(kind: str, size: int = 18, *, selected: bool = False) -> QPixmap:
    """Squircle-плитка с SF-Symbols-подобной иконкой (для sidebar).

    kind: home | history | settings | about
    Используется в навигации главного окна.
    Когда selected=True — плитка прозрачная белая (контраст с синим выделением).
    """
    cache_key = (int(size), hash((kind, selected)) & 0xFFFFFFFF)
    cached = _MIC_PIXMAP_CACHE.get(cache_key)
    if cached is not None:
        return cached

    pix = QPixmap(QSize(size, size))
    pix.fill(Qt.GlobalColor.transparent)
    p = QPainter(pix)
    p.setRenderHint(QPainter.RenderHint.Antialiasing)

    s = float(size)
    rect = QRectF(0, 0, s, s)

    # Цвет плитки: при selected — полупрозрачный белый, иначе цветной по типу.
    if selected:
        tile_color = QColor(255, 255, 255, 70)
        glyph_color = QColor(255, 255, 255)
    else:
        tile_hex = _NAV_ICON_TILES.get(kind, "#8E8E93")
        tile_color = QColor(tile_hex)
        glyph_color = QColor(255, 255, 255)

    # Squircle подложка
    p.setBrush(tile_color)
    p.setPen(Qt.PenStyle.NoPen)
    p.drawPath(_squircle_path(rect, 0.26))

    # Глиф (тонкая линия, белая)
    pen = QPen(glyph_color, max(1.0, s * 0.10))
    pen.setCapStyle(Qt.PenCapStyle.RoundCap)
    pen.setJoinStyle(Qt.PenJoinStyle.RoundJoin)
    p.setPen(pen)
    p.setBrush(Qt.BrushStyle.NoBrush)

    # Внутренний box для глифа
    inset = s * 0.22
    g = QRectF(inset, inset, s - 2 * inset, s - 2 * inset)

    if kind == "home":
        # Дом: треугольная крыша + прямоугольник
        path = QPainterPath()
        path.moveTo(g.left(), g.center().y() + g.height() * 0.05)
        path.lineTo(g.center().x(), g.top())
        path.lineTo(g.right(), g.center().y() + g.height() * 0.05)
        p.drawPath(path)
        # «Стены»
        wall_top = g.center().y() + g.height() * 0.05
        path2 = QPainterPath()
        path2.moveTo(g.left() + g.width() * 0.12, wall_top)
        path2.lineTo(g.left() + g.width() * 0.12, g.bottom())
        path2.lineTo(g.right() - g.width() * 0.12, g.bottom())
        path2.lineTo(g.right() - g.width() * 0.12, wall_top)
        p.drawPath(path2)
    elif kind == "history":
        # Часы: круг + стрелки
        p.drawEllipse(g)
        cx, cy = g.center().x(), g.center().y()
        r = g.width() / 2
        p.drawLine(QPointF(cx, cy), QPointF(cx, cy - r * 0.55))
        p.drawLine(QPointF(cx, cy), QPointF(cx + r * 0.40, cy))
    elif kind == "settings":
        # Шестерёнка-минимализм: круг + 6 насечек
        # рисуем как восьмиугольную звезду, чтобы было читаемо в 18px
        cx, cy = g.center().x(), g.center().y()
        r_outer = g.width() / 2
        r_inner = r_outer * 0.62
        p.drawEllipse(QRectF(cx - r_inner * 0.45, cy - r_inner * 0.45,
                             r_inner * 0.9, r_inner * 0.9))
        import math as _m
        for i in range(8):
            ang = _m.radians(i * 45)
            x1 = cx + _m.cos(ang) * r_inner
            y1 = cy + _m.sin(ang) * r_inner
            x2 = cx + _m.cos(ang) * r_outer
            y2 = cy + _m.sin(ang) * r_outer
            p.drawLine(QPointF(x1, y1), QPointF(x2, y2))
    elif kind == "about":
        # Кружок «i»
        p.drawEllipse(g)
        cx, cy = g.center().x(), g.center().y()
        # Точка
        dot_r = max(1.0, s * 0.06)
        p.setBrush(glyph_color)
        p.setPen(Qt.PenStyle.NoPen)
        p.drawEllipse(QPointF(cx, cy - g.height() * 0.20), dot_r, dot_r)
        # Стержень
        stem_pen = QPen(glyph_color, max(1.0, s * 0.10))
        stem_pen.setCapStyle(Qt.PenCapStyle.RoundCap)
        p.setPen(stem_pen)
        p.drawLine(QPointF(cx, cy - g.height() * 0.05),
                   QPointF(cx, cy + g.height() * 0.25))

    p.end()

    if len(_MIC_PIXMAP_CACHE) >= _MIC_PIXMAP_CACHE_LIMIT:
        _MIC_PIXMAP_CACHE.pop(next(iter(_MIC_PIXMAP_CACHE)))
    _MIC_PIXMAP_CACHE[cache_key] = pix
    return pix


def make_chevron_pixmap(size: int = 12, color: QColor | None = None) -> QPixmap:
    """Маленький chevron `›` (Apple disclosure indicator)."""
    pix = QPixmap(QSize(size, size))
    pix.fill(Qt.GlobalColor.transparent)
    p = QPainter(pix)
    p.setRenderHint(QPainter.RenderHint.Antialiasing)
    c = color or QColor(0xC7, 0xC7, 0xCC)
    pen = QPen(c, max(1.2, size * 0.12))
    pen.setCapStyle(Qt.PenCapStyle.RoundCap)
    pen.setJoinStyle(Qt.PenJoinStyle.RoundJoin)
    p.setPen(pen)
    s = float(size)
    p.drawLine(QPointF(s * 0.40, s * 0.28), QPointF(s * 0.62, s * 0.50))
    p.drawLine(QPointF(s * 0.62, s * 0.50), QPointF(s * 0.40, s * 0.72))
    p.end()
    return pix


def make_status_badge_pixmap(kind: str, size: int = 16) -> QPixmap:
    """Круглый Apple-style badge: ✓ (success), ✗ (error), ! (warning).

    kind: ok | error | warning
    Цвета — system green / red / orange. Глиф — белый внутри.
    """
    pix = QPixmap(QSize(size, size))
    pix.fill(Qt.GlobalColor.transparent)
    p = QPainter(pix)
    p.setRenderHint(QPainter.RenderHint.Antialiasing)

    s = float(size)
    if kind == "ok":
        bg = QColor(0x34, 0xC7, 0x59)        # system green
    elif kind == "error":
        bg = QColor(0xFF, 0x3B, 0x30)        # system red
    elif kind == "warning":
        bg = QColor(0xFF, 0x95, 0x00)        # system orange
    else:
        bg = QColor(0x86, 0x86, 0x8B)        # system gray

    p.setBrush(bg)
    p.setPen(Qt.PenStyle.NoPen)
    p.drawEllipse(QRectF(0, 0, s, s))

    # Глиф
    pen = QPen(QColor(255, 255, 255), max(1.4, s * 0.14))
    pen.setCapStyle(Qt.PenCapStyle.RoundCap)
    pen.setJoinStyle(Qt.PenJoinStyle.RoundJoin)
    p.setPen(pen)
    p.setBrush(Qt.BrushStyle.NoBrush)

    if kind == "ok":
        # Галочка
        p.drawLine(QPointF(s * 0.28, s * 0.52), QPointF(s * 0.45, s * 0.68))
        p.drawLine(QPointF(s * 0.45, s * 0.68), QPointF(s * 0.74, s * 0.36))
    elif kind == "error":
        # Крест
        p.drawLine(QPointF(s * 0.32, s * 0.32), QPointF(s * 0.68, s * 0.68))
        p.drawLine(QPointF(s * 0.68, s * 0.32), QPointF(s * 0.32, s * 0.68))
    elif kind == "warning":
        # Восклицательный
        p.drawLine(QPointF(s * 0.5, s * 0.28), QPointF(s * 0.5, s * 0.58))
        p.setBrush(QColor(255, 255, 255))
        p.setPen(Qt.PenStyle.NoPen)
        dot_r = max(1.0, s * 0.08)
        p.drawEllipse(QPointF(s * 0.5, s * 0.72), dot_r, dot_r)

    p.end()
    return pix


# ---------------------------------------------------------------------------
# History helpers
# ---------------------------------------------------------------------------


class _HistoryEntry(NamedTuple):
    ts: datetime
    text: str


# Mtime-кеш чтения истории: повторные вызовы _read_history без изменений на диске
# возвращают тот же список — не открываем JSONL по второму разу.
_HISTORY_CACHE: dict[int, tuple[tuple[float, ...], list[_HistoryEntry]]] = {}


def _read_history(days: int = 7) -> list[_HistoryEntry]:
    root = app_data_dir() / "backups"
    if not root.exists():
        return []

    # Собираем актуальные пути JSONL и их mtime — это «отпечаток» состояния диска.
    cutoff = datetime.now(UTC) - timedelta(days=days)
    files: list[tuple[Path, float]] = []
    for day_dir in sorted(root.iterdir(), reverse=True):
        if not day_dir.is_dir():
            continue
        try:
            day_dt = datetime.strptime(day_dir.name, "%Y-%m-%d").replace(tzinfo=UTC)
        except ValueError:
            continue
        if day_dt < cutoff:
            break
        jsonl = day_dir / "dictations.jsonl"
        if jsonl.exists():
            try:
                files.append((jsonl, jsonl.stat().st_mtime))
            except OSError:
                pass

    fingerprint = tuple(m for _, m in files)
    cached = _HISTORY_CACHE.get(days)
    if cached is not None and cached[0] == fingerprint:
        return list(cached[1])  # копия — мутации UI не должны портить кеш

    entries: list[_HistoryEntry] = []
    for jsonl, _mtime in files:
        try:
            text = jsonl.read_text(encoding="utf-8")
        except OSError:
            continue
        for line in text.splitlines():
            line = line.strip()
            if not line:
                continue
            try:
                obj = json.loads(line)
                ts = datetime.fromisoformat(obj["ts"])
                if not ts.tzinfo:
                    ts = ts.replace(tzinfo=UTC)
                entries.append(_HistoryEntry(ts=ts, text=obj["text"]))
            except Exception:
                continue
    entries.sort(key=lambda e: e.ts, reverse=True)
    _HISTORY_CACHE[days] = (fingerprint, list(entries))
    return entries


def _date_label(ts: datetime) -> str:
    today = datetime.now().date()
    d = ts.date()
    if d == today:
        return "Сегодня"
    if d == today - timedelta(days=1):
        return "Вчера"
    months = [
        "", "января", "февраля", "марта", "апреля", "мая", "июня",
        "июля", "августа", "сентября", "октября", "ноября", "декабря",
    ]
    return f"{d.day} {months[d.month]} {d.year}"


