class _ModeDialog(QDialog):
    def __init__(self, current: str, parent: QWidget | None = None) -> None:
        super().__init__(parent)
        self.setWindowTitle("Режим распознавания")
        self.setMinimumWidth(420)
        self.setStyleSheet(_QSS)

        layout = QVBoxLayout(self)
        layout.setSpacing(4)
        layout.setContentsMargins(28, 24, 28, 22)

        title = QLabel("Режим распознавания")
        title.setObjectName("pageTitle")
        title.setStyleSheet("font-size: 18px; font-weight: 700;")
        layout.addWidget(title)
        layout.addSpacing(4)

        hint = QLabel("Чем глубже анализ, тем точнее распознавание, но дольше пауза перед вставкой.")
        hint.setObjectName("mutedText")
        hint.setWordWrap(True)
        layout.addWidget(hint)
        layout.addSpacing(12)

        self._group = QButtonGroup(self)
        self._radios: dict[str, QRadioButton] = {}

        for key in ("fast", "standard", "precise"):
            rb = QRadioButton(self)
            rb.setText(f"{_MODE_LABELS[key]}  —  {_MODE_DESCRIPTIONS[key]}")
            rb.setChecked(key == current)
            self._group.addButton(rb)
            self._radios[key] = rb
            layout.addWidget(rb)

        layout.addSpacing(14)
        btns = QDialogButtonBox(
            QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel
        )
        btns.button(QDialogButtonBox.StandardButton.Ok).setText("Применить")
        btns.button(QDialogButtonBox.StandardButton.Cancel).setText("Отмена")
        btns.accepted.connect(self.accept)
        btns.rejected.connect(self.reject)
        layout.addWidget(btns)

    @property
    def selected_mode(self) -> str:
        for key, rb in self._radios.items():
            if rb.isChecked():
                return key
        return "standard"


