def _hotkey_pill(text: str, parent: QWidget | None = None) -> QLabel:
    lbl = QLabel(text.upper(), parent)
    lbl.setObjectName("hotkeyPill")
    lbl.setAlignment(Qt.AlignmentFlag.AlignCenter)
    return lbl


def _hotkey_row(combination: str, parent: QWidget | None = None) -> QWidget:
    container = QWidget(parent)
    container.setStyleSheet("background: transparent;")
    hl = QHBoxLayout(container)
    hl.setContentsMargins(0, 0, 0, 0)
    hl.setSpacing(8)

    parts = [p for p in combination.split("+") if p]
    for i, part in enumerate(parts):
        hl.addWidget(_hotkey_pill(part, container))
        if i < len(parts) - 1:
            plus = QLabel("+", container)
            plus.setObjectName("hotkeyPlus")
            plus.setAlignment(Qt.AlignmentFlag.AlignCenter)
            hl.addWidget(plus)

    hl.addStretch()
    return container


def _h_divider() -> QFrame:
    f = QFrame()
    f.setObjectName("divider")
    f.setFixedHeight(1)
    return f


def _h_divider_inset(left_inset: int = 16) -> QWidget:
    """Apple-style row separator: 1px line, отступ слева как у row content."""
    w = QWidget()
    w.setStyleSheet("background: transparent;")
    w.setFixedHeight(1)
    hl = QHBoxLayout(w)
    hl.setContentsMargins(left_inset, 0, 0, 0)
    hl.setSpacing(0)
    line = QFrame()
    line.setObjectName("divider")
    line.setFixedHeight(1)
    hl.addWidget(line, 1)
    return w


