    def _build_status_panel(self) -> QFrame:
        """Four-row status panel: ASR / Hotkey / Microphone / Disk.

        Apple-style: круглый badge слева, имя в средней колонке (приглушённое),
        значение в правой (primary), опциональная chevron-кнопка.
        """
        from voice_typing_ru.app.preflight import (
            check_disk_space,
            check_hotkey,
            check_microphone,
        )

        panel = QFrame()
        panel.setObjectName("card")
        pl = QVBoxLayout(panel)
        pl.setContentsMargins(0, 0, 0, 0)
        pl.setSpacing(0)

        def _row(kind: str, label: str, value: str, action: object | None = None) -> QWidget:
            row = QWidget()
            row.setStyleSheet("background: transparent;")
            row.setFixedHeight(40)
            hl = QHBoxLayout(row)
            hl.setContentsMargins(16, 0, 12, 0)
            hl.setSpacing(10)

            badge = QLabel()
            badge.setPixmap(make_status_badge_pixmap(kind, 14))
            badge.setFixedSize(QSize(14, 14))
            badge.setStyleSheet("background: transparent;")

            name_lbl = QLabel(label)
            name_lbl.setObjectName("settingLabel")
            name_lbl.setMinimumWidth(140)

            val_lbl = QLabel(value)
            val_lbl.setObjectName("settingValue")
            val_lbl.setAlignment(Qt.AlignmentFlag.AlignRight | Qt.AlignmentFlag.AlignVCenter)

            hl.addWidget(badge)
            hl.addWidget(name_lbl)
            hl.addWidget(val_lbl, 1)

            if action is not None:
                link = QPushButton()
                link.setIcon(QIcon(make_chevron_pixmap(11, QColor(0xC7, 0xC7, 0xCC))))
                link.setIconSize(QSize(11, 11))
                link.setFlat(True)
                link.setFixedSize(QSize(22, 22))
                link.setCursor(Qt.CursorShape.PointingHandCursor)
                link.setStyleSheet(
                    "QPushButton { background: transparent; border: none; } "
                    "QPushButton:hover { background: rgba(0,0,0,0.04); border-radius: 4px; }"
                )
                link.clicked.connect(action)
                hl.addWidget(link)
            return row

        rows: list[QWidget] = []

        # Microphone
        mic_result = check_microphone()
        if mic_result.ok:
            rows.append(_row("ok", "Микрофон", "доступен"))
        else:
            rows.append(_row("error", "Микрофон", "не найден", self._change_mic))

        # Hotkey
        hk_result = check_hotkey(self._config.hotkey.combination)
        hk_label = self._format_hotkey(self._config.hotkey.combination) or "не задана"
        if hk_result.ok:
            rows.append(_row("ok", "Горячая клавиша", hk_label))
        else:
            rows.append(_row("error", "Горячая клавиша", "невалидна", self._change_hotkey))

        # ASR engine
        engine_label = "GigaAM v3" if self._config.asr.engine == "gigaam" else self._config.asr.engine.title()
        rows.append(_row("ok", "Движок ASR", engine_label, self._open_advanced))

        # Disk space
        disk_result = check_disk_space()
        if disk_result.ok:
            try:
                import shutil
                free_gb = shutil.disk_usage(Path.home()).free / (1024 ** 3)
                rows.append(_row("ok", "Диск", f"{free_gb:.1f} ГБ свободно"))
            except Exception:
                rows.append(_row("ok", "Диск", "достаточно"))
        else:
            rows.append(_row("warning", "Диск", "мало места"))

        for i, r in enumerate(rows):
            pl.addWidget(r)
            if i < len(rows) - 1:
                pl.addWidget(_h_divider_inset(40))  # отступ под значок

        return panel

