    def _reload_history(self) -> None:
        while self._hist_layout.count() > 1:
            item = self._hist_layout.takeAt(0)
            if item.widget():
                item.widget().deleteLater()

        disk = _read_history(days=7)
        combined = list(disk) + list(self._session_entries)
        seen: set[tuple[str, str]] = set()
        unique: list[_HistoryEntry] = []
        for e in combined:
            key = (e.ts.isoformat()[:16], e.text[:40])
            if key not in seen:
                seen.add(key)
                unique.append(e)
        unique.sort(key=lambda e: e.ts, reverse=True)

        if not unique:
            empty = QLabel(
                "Нет записей за последние 7 дней.\nНачни диктовать — они появятся здесь."
            )
            empty.setObjectName("historyEmpty")
            empty.setAlignment(Qt.AlignmentFlag.AlignCenter)
            empty.setContentsMargins(0, 60, 0, 0)
            self._hist_layout.insertWidget(0, empty)
            return

        # Group by date
        current_date = ""
        pos = 0
        date_card: QFrame | None = None
        date_card_layout: QVBoxLayout | None = None

        for entry in unique:
            local_ts = entry.ts.astimezone()
            dl = _date_label(local_ts)
            if dl != current_date:
                # New date section
                current_date = dl
                if pos > 0:
                    spacer = QWidget()
                    spacer.setFixedHeight(20)
                    spacer.setStyleSheet("background: transparent;")
                    self._hist_layout.insertWidget(pos, spacer)
                    pos += 1
                date_lbl = QLabel(dl)
                date_lbl.setObjectName("sectionHeader")
                date_lbl.setContentsMargins(4, 0, 0, 8)
                self._hist_layout.insertWidget(pos, date_lbl)
                pos += 1
                # New card for this date's entries
                date_card = QFrame()
                date_card.setObjectName("card")
                date_card_layout = QVBoxLayout(date_card)
                date_card_layout.setContentsMargins(0, 0, 0, 0)
                date_card_layout.setSpacing(0)
                self._hist_layout.insertWidget(pos, date_card)
                pos += 1

            assert date_card_layout is not None
            if date_card_layout.count() > 0:
                date_card_layout.addWidget(_h_divider())
            date_card_layout.addWidget(self._make_history_row(local_ts, entry.text))

    def _make_history_row(self, ts: datetime, text: str) -> QWidget:
        row = QWidget()
        row.setStyleSheet("background: transparent;")
        rl = QHBoxLayout(row)
        rl.setContentsMargins(20, 13, 20, 13)
        rl.setSpacing(18)

        time_lbl = QLabel(ts.strftime("%H:%M"))
        time_lbl.setObjectName("historyTime")
        time_lbl.setFixedWidth(46)
        time_lbl.setAlignment(Qt.AlignmentFlag.AlignTop | Qt.AlignmentFlag.AlignRight)

        text_lbl = QLabel(text)
        text_lbl.setObjectName("historyText")
        text_lbl.setWordWrap(True)
        text_lbl.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Preferred)

        rl.addWidget(time_lbl)
        rl.addWidget(text_lbl)
        return row

