    @staticmethod
    def _section_header(title: str) -> QLabel:
        """Apple-style section header: bold mixed-case, без UPPERCASE."""
        lbl = QLabel(title)
        lbl.setObjectName("sectionHeader")
        lbl.setContentsMargins(4, 0, 0, 6)
        return lbl

    def _setting_row(
        self,
        parent: QWidget,
        label: str,
        value: str,
        on_change: object,
        btn_text: str = "Изменить",
    ) -> QWidget:
        """Apple-style row: label + value слева, кнопка-action справа.

        Эталон — macOS System Settings rows: 16/14 padding, 13px text,
        value приглушённо под label, кнопка справа с тонким border.
        """
        row = QWidget(parent)
        row.setObjectName("settingRow")
        rl = QHBoxLayout(row)
        rl.setContentsMargins(16, 12, 14, 12)
        rl.setSpacing(12)

        # Left: name + value (stacked, Apple-style description row)
        left = QVBoxLayout()
        left.setSpacing(2)
        left.setContentsMargins(0, 0, 0, 0)

        name_lbl = QLabel(label)
        name_lbl.setObjectName("settingLabel")
        val_lbl = QLabel(value)
        val_lbl.setObjectName("settingValue")
        val_lbl.setWordWrap(False)
        left.addWidget(name_lbl)
        left.addWidget(val_lbl)

        left_w = QWidget()
        left_w.setStyleSheet("background: transparent;")
        left_w.setLayout(left)

        btn = QPushButton(btn_text)
        btn.setObjectName("changeBtn")
        btn.setMinimumWidth(78)
        btn.setCursor(Qt.CursorShape.PointingHandCursor)
        btn.clicked.connect(on_change)

        rl.addWidget(left_w, 1)
        rl.addWidget(btn, 0, Qt.AlignmentFlag.AlignVCenter)

        row._val_lbl = val_lbl  # type: ignore[attr-defined]
        return row

    @staticmethod
    def _format_hotkey(combination: str) -> str:
        """Превратить 'ctrl+win+space' в 'Ctrl + Win + Space'."""
        return " + ".join(p.strip().capitalize() for p in combination.split("+") if p)

    def _change_hotkey(self) -> None:
        from voice_typing_ru.ui.settings_window import SettingsWindow

        win = SettingsWindow(self._config, self._settings_path, self)
        win.config_saved.connect(self._on_config_saved)
        win._tabs.setCurrentIndex(1)
        win.exec()

    def _change_mic(self) -> None:
        from voice_typing_ru.ui.settings_window import SettingsWindow

        win = SettingsWindow(self._config, self._settings_path, self)
        win.config_saved.connect(self._on_config_saved)
        win._tabs.setCurrentIndex(0)
        win.exec()

    def _change_mode(self) -> None:
        dlg = _ModeDialog(self._config.recognition_mode, self)
        if dlg.exec() == QDialog.DialogCode.Accepted:
            mode = dlg.selected_mode
            from voice_typing_ru.domain.config import save_config

            new_cfg = self._config.model_copy(update={"recognition_mode": mode})
            save_config(new_cfg, self._settings_path)
            self._on_config_saved(new_cfg)

    def _open_advanced(self) -> None:
        from voice_typing_ru.ui.settings_window import SettingsWindow

        win = SettingsWindow(self._config, self._settings_path, self)
        win.config_saved.connect(self._on_config_saved)
        win.exec()

    def _on_config_saved(self, new_cfg: AppConfig) -> None:
        self._config = new_cfg
        self._refresh_settings_rows()
        # Update home stats
        try:
            self._stat_streak_lbl.setText(
                _MODE_LABELS.get(new_cfg.recognition_mode, "Стандартный")
            )
        except AttributeError:
            pass
        self.config_saved.emit(new_cfg)

    def _refresh_settings_rows(self) -> None:
        cfg = self._config
        hotkey_str = self._format_hotkey(cfg.hotkey.combination)
        mode_ru = "удержание" if cfg.hotkey.mode == "push_to_talk" else "переключение"
        self._set_row_value(self._row_hotkey, f"{hotkey_str}  ·  {mode_ru}")

        device = cfg.audio.device
        self._set_row_value(
            self._row_mic, "Системный по умолчанию" if device is None else str(device)
        )
        self._set_row_value(
            self._row_mode, _MODE_LABELS.get(cfg.recognition_mode, "Стандартный")
        )

    @staticmethod
    def _set_row_value(row: QWidget, value: str) -> None:
        lbl = getattr(row, "_val_lbl", None)
        if isinstance(lbl, QLabel):
            lbl.setText(value)

