        info_card.setObjectName("card")
        info_layout = QVBoxLayout(info_card)
        info_layout.setContentsMargins(0, 0, 0, 0)
        info_layout.setSpacing(0)

        info_items = [
            ("Движок ASR", "GigaAM v3 (Сбер, MIT)"),
            ("Лицензия", "MIT"),
            ("Автор", "Vladislav Chadaev / RedPeak"),
            ("Горячая клавиша по умолчанию", "Ctrl + Win + Space"),
        ]
        for i, (label, value) in enumerate(info_items):
            row = QWidget()
            row.setStyleSheet("background: transparent;")
            row.setFixedHeight(40)
            rl = QHBoxLayout(row)
            rl.setContentsMargins(20, 0, 20, 0)
            rl.setSpacing(12)
            k = QLabel(label)
            k.setObjectName("settingLabel")
            k.setMinimumWidth(220)
            v = QLabel(value)
            v.setObjectName("settingValue")
            v.setStyleSheet(f"color: {_C_TEXT_PRIMARY};")
            v.setAlignment(Qt.AlignmentFlag.AlignRight | Qt.AlignmentFlag.AlignVCenter)
            rl.addWidget(k)
            rl.addWidget(v, 1)
            info_layout.addWidget(row)
            if i < len(info_items) - 1:
                info_layout.addWidget(_h_divider_inset(20))

        layout.addWidget(info_card)

        # Diagnostic bundle button (M2.3)
        diag_btn = QPushButton("Скачать диагностику")
        diag_btn.setObjectName("changeBtn")
        diag_btn.setFixedWidth(200)
        diag_btn.setCursor(Qt.CursorShape.PointingHandCursor)
        diag_btn.clicked.connect(self._download_diagnostic)
        diag_row = QHBoxLayout()
        diag_row.addStretch()
        diag_row.addWidget(diag_btn)
        diag_row.addStretch()
        layout.addSpacing(8)
        layout.addLayout(diag_row)

        layout.addStretch()
        return page

    def _download_diagnostic(self) -> None:
        """Collect diagnostic bundle and save to a user-chosen path."""
        import os
        from PySide6.QtWidgets import QFileDialog, QMessageBox
        try:
            sys.path.insert(0, str(Path(__file__).parent.parent.parent.parent.parent / "scripts"))
            from collect_diag import collect_to_buffer  # type: ignore[import-untyped]
            data, _meta = collect_to_buffer()
        except Exception as exc:
            QMessageBox.warning(self, "Диагностика", f"Не удалось собрать данные:\n{exc}")
            return

        import datetime
        ts = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
        default = str(Path.home() / f"voicetyping_diag_{ts}.zip")
        path, _ = QFileDialog.getSaveFileName(
            self, "Сохранить диагностику", default, "ZIP-архивы (*.zip)"
        )
        if path:
            Path(path).write_bytes(data)
            os.startfile(str(Path(path).parent))

    # ------------------------------------------------------------------
    # Public API — called by app.py on each transcription
    # ------------------------------------------------------------------

    def add_history_entry(self, text: str, ts: datetime | None = None) -> None:
        """Добавить запись о новой диктовке. Вызывается из ui/app.py.

        Если страница «История» сейчас не видна, обновление UI откладываем —
        перерисуем при следующем переключении на неё (через _select_page).
        Иначе пробуем добавить только одну строку, без полного перестроения
        (но это требует валидной структуры; если её нет — fallback к перерисовке).
        """
        entry = _HistoryEntry(ts=ts or datetime.now(UTC), text=text)
        self._session_entries.insert(0, entry)
        words = len(text.split())
        self._session_word_count += words
        # Update home page stats — это всегда дёшево.
        self._stat_words_lbl.setText(str(self._session_word_count))
        self._stat_entries_lbl.setText(str(len(self._session_entries)))
        self._recent_lbl.setText(text)
        # История перерисовывается только если её страница активна.
        # (Иначе — отметим «грязно», перерисуем при переключении.)
        self._history_dirty = True
        if self._stack.currentIndex() == 1:  # 1 == история
            self._reload_history()
            self._history_dirty = False

    def update_config(self, config: AppConfig) -> None:
        """Вызывается когда конфиг изменился извне (например, через старый SettingsWindow)."""
        self._config = config
        self._refresh_settings_rows()
        try:
            self._stat_streak_lbl.setText(
                _MODE_LABELS.get(config.recognition_mode, "Стандартный")
            )
        except AttributeError:
            pass

